1	interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: QuoteItem[];
10	}
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: QuoteStep[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  amulet: 60,
19	  sword: 100,
20	};
21	
22	const FIRST_INSURANCE_RATE = 0.1;
23	const PROCESSING_FEE = 5;
24	
25	const CURSE_SURCHARGE_RATE = 0.5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const LOYALTY_DISCOUNT_RATE = 0.2;
29	const LOYALTY_THRESHOLD_YEARS = 2;
30	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
31	
32	function sumOver<T>(xs: T[], f: (x: T) => number): number {
33	  return xs.reduce((total, x) => total + f(x), 0);
34	}
35	
36	function itemBasePremium(item: QuoteItem): number {
37	  return BASE_PREMIUM[item.type] ?? 0;
38	}
39	
40	function itemSurcharges(item: QuoteItem): number {
41	  const base = itemBasePremium(item);
42	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
43	  const highEnchantmentSurcharge =
44	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
45	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
46	      : 0;
47	  return curseSurcharge + highEnchantmentSurcharge;
48	}
49	
50	function priceQuoteStep(
51	  step: QuoteStep,
52	  yearsWithMHPCO: number,
53	  isFollowUp: boolean,
54	): { premium: number } {
55	  const policyBase = sumOver(step.items, itemBasePremium);
56	  const itemSurchargeTotal = sumOver(step.items, itemSurcharges);
57	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
58	  const loyaltyDiscount =
59	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
60	      ? policyBase * LOYALTY_DISCOUNT_RATE
61	      : 0;
62	  const followUpDiscount = isFollowUp
63	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
64	    : 0;
65	  const premium = Math.ceil(
66	    policyBase +
67	      itemSurchargeTotal +
68	      firstInsurance -
69	      loyaltyDiscount -
70	      followUpDiscount +
71	      PROCESSING_FEE,
72	  );
73	  return { premium };
74	}
75	
76	export function runScenario(scenario: Scenario): {
77	  results: { premium: number }[];
78	} {
79	  const results = scenario.steps.map((step, index) =>
80	    priceQuoteStep(step, scenario.customer.yearsWithMHPCO, index > 0),
81	  );
82	  return { results };
83	}
